	minSessionTimeout        = 1 * time.Second
	agentRuntimeGVR          = schema.GroupVersionResource{Group: "runtime.agentcube.volcano.sh", Version: "v1alpha1", Resource: "agentruntimes"}
)

func (r *AgentRuntime) ValidateCreate() error {
	var allErrs field.ErrorList

	if r.Spec.Template == nil {
		allErrs = append(allErrs, field.Required(field.NewPath("spec", "podTemplate"), "template is required"))
	}

	if r.Spec.SessionTimeout != nil {
		timeout := r.Spec.SessionTimeout.Duration
		if timeout < minSessionTimeout {
			allErrs = append(allErrs, field.Invalid(field.NewPath("spec", "sessionTimeout"), timeout, "sessionTimeout must be at least 1 second"))
		}
		if timeout > maxSessionTimeout {
			allErrs = append(allErrs, field.Invalid(field.NewPath("spec", "sessionTimeout"), timeout, fmt.Sprintf("sessionTimeout must not exceed %v", maxSessionTimeout)))
		}
	}

	if r.Spec.MaxSessionDuration != nil && r.Spec.SessionTimeout != nil {
		if r.Spec.MaxSessionDuration.Duration < r.Spec.SessionTimeout.Duration {
			allErrs = append(allErrs, field.Invalid(field.NewPath("spec", "maxSessionDuration"), r.Spec.MaxSessionDuration.Duration, "maxSessionDuration must be greater than or equal to sessionTimeout"))
		}
	}

	for i, port := range r.Spec.Ports {
		idxPath := field.NewPath("spec", "targetPort").Index(i)
		if port.Port < 1 || port.Port > 65535 {
			allErrs = append(allErrs, field.Invalid(idxPath.Child("port"), port.Port, "port must be between 1 and 65535"))
		}
		if port.Protocol != ProtocolHTTP && port.Protocol != ProtocolHTTPS {
			allErrs = append(allErrs, field.NotSupported(idxPath.Child("protocol"), port.Protocol, []string{"HTTP", "HTTPS"}))
		}
	}

	if len(allErrs) == 0 {
		return nil
	}

	return apierrors.NewInvalid(agentRuntimeGVR.GroupResource(), r.Name, allErrs)
}

