		if len(oldObj.Spec.Ports) != len(r.Spec.Ports) {
			allErrs = append(allErrs, field.Forbidden(field.NewPath("spec", "targetPort"), "ports are immutable"))
		} else {
			for i := range oldObj.Spec.Ports {
