package workloadmanager

import (
	"context"
	"fmt"
	"time"

	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/runtime/schema"
	"k8s.io/client-go/dynamic"
	dynamicinformer "k8s.io/client-go/dynamic/dynamicinformer"
	"k8s.io/client-go/informers"
	"k8s.io/client-go/tools/cache"
)

var (
	AgentRuntimeGVR    = schema.GroupVersionResource{Group: "runtime.agentcube.volcano.sh", Version: "v1alpha1", Resource: "agentruntimes"}
	CodeInterpreterGVR = schema.GroupVersionResource{Group: "runtime.agentcube.volcano.sh", Version: "v1alpha1", Resource: "codeinterpreters"}
	SandboxGVR         = schema.GroupVersionResource{Group: "sandbox.x-k8s.io", Version: "v1alpha1", Resource: "sandboxes"}
	SandboxClaimGVR    = schema.GroupVersionResource{Group: "sandbox.x-k8s.io", Version: "v1alpha1", Resource: "sandboxclaims"}
)

type Informers struct {
	dynamicClient    dynamic.Interface
	factory          dynamicinformer.DynamicSharedInformerFactory
	podInformer      cache.SharedIndexInformer
	podLister        cache.GenericLister
	informerSynced   map[schema.GroupVersionResource]cache.InformerSynced
	stopCh           <-chan struct{}
}

func NewInformers(dynamicClient dynamic.Interface, stopCh <-chan struct{}) *Informers {
	factory := dynamicinformer.NewDynamicSharedInformerFactory(dynamicClient, 15*time.Minute)

	return &Informers{
		dynamicClient:  dynamicClient,
		factory:        factory,
		stopCh:         stopCh,
		informerSynced: make(map[schema.GroupVersionResource]cache.InformerSynced),
	}
}

func (i *Informers) Start(ctx context.Context, kubeClient informers.SharedInformerFactory) error {
	i.factory.ForResource(SandboxGVR)
	i.factory.ForResource(SandboxClaimGVR)

	i.factory.Start(ctx.Done())

	kubeInformerFactory := kubeClient
	i.podInformer = kubeInformerFactory.Core().V1().Pods().Informer()
	i.podLister = kubeInformerFactory.Core().V1().Pods().Lister()

	kubeInformerFactory.Start(ctx.Done())

	i.informerSynced[AgentRuntimeGVR] = i.factory.ForResource(AgentRuntimeGVR).Informer().HasSynced
	i.informerSynced[CodeInterpreterGVR] = i.factory.ForResource(CodeInterpreterGVR).Informer().HasSynced
	i.informerSynced[SandboxGVR] = i.factory.ForResource(SandboxGVR).Informer().HasSynced
	i.informerSynced[SandboxClaimGVR] = i.factory.ForResource(SandboxClaimGVR).Informer().HasSynced
	i.informerSynced[corev1.SchemeGroupVersion.WithResource("pods")] = i.podInformer.HasSynced

	return nil
}

func (i *Informers) WaitForCacheSync(timeout time.Duration) error {
	ctx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()

	return i.WaitForCacheSyncWithContext(ctx)
}

func (i *Informers) WaitForCacheSyncWithContext(ctx context.Context) error {
	for gvr, synced := range i.informerSynced {
		if !cache.WaitForCacheSync(ctx.Done(), synced) {
			return fmt.Errorf("informer failed to sync for %v", gvr)
		}
	}

	if !cache.WaitForCacheSync(ctx.Done(), i.podInformer.HasSynced) {
		return fmt.Errorf("pod informer failed to sync")
	}

	return nil
}

func (i *Informers) HasSynced() bool {
	for _, synced := range i.informerSynced {
		if !synced() {
			return false
		}
	}

	return i.podInformer.HasSynced()
}

