package workloadmanager

import (
	"context"
	"crypto/rsa"
	"fmt"
	"strings"
	"sync"
	"time"

	authv1 "k8s.io/api/authentication/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"

	"github.com/gin-gonic/gin"
)

type TokenCache struct {
	cache map[string]*cacheEntry
	mu    sync.RWMutex
	size  int
	ttl   time.Duration
}

type cacheEntry struct {
	username         string
	namespace        string
	serviceAccount   string
	expiresAt        time.Time
	publicKey        *rsa.PublicKey
	serviceAccountNS string
}

func NewTokenCache(size int, ttl time.Duration) *TokenCache {
	return &TokenCache{
		cache: make(map[string]*cacheEntry),
		size:  size,
		ttl:   ttl,
	}
}

func (tc *TokenCache) Get(token string) (*cacheEntry, bool) {
	tc.mu.RLock()
	defer tc.mu.RUnlock()
	entry, ok := tc.cache[token]
	if !ok {
		return nil, false
	}
	if time.Now().After(entry.expiresAt) {
		return nil, false
	}
	return entry, true
}

func (tc *TokenCache) Set(token string, entry *cacheEntry) {
	tc.mu.Lock()
	defer tc.Unlock()

	if len(tc.cache) >= tc.size {
		for k := range tc.cache {
			delete(tc.cache, k)
			break
		}
	}

	entry.expiresAt = time.Now().Add(tc.ttl)
	tc.cache[token] = entry
}

func (tc *TokenCache) Delete(token string) {
	tc.mu.Lock()
	defer tc.Unlock()
	delete(tc.cache, token)
}

func (s *Server) AuthMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		if !s.config.EnableAuth {
			c.Next()
			return
		}

		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(401, gin.H{"error": "Missing authorization header"})
			c.Abort()
			return
		}

		parts := strings.Split(authHeader, " ")
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.JSON(401, gin.H{"error": "Invalid authorization format"})
			c.Abort()
			return
		}

		token := parts[1]

		if entry, ok := s.tokenCache.Get(token); ok {
			c.Set("username", entry.username)
			c.Set("namespace", entry.namespace)
			c.Set("serviceAccount", entry.serviceAccount)
			c.Next()
			return
		}

		username, namespace, saName, err := validateServiceAccountToken(s.k8sClient.clientset, token, s.config.RuntimeNamespace)
		if err != nil {
			c.JSON(401, gin.H{"error": err.Error()})
			c.Abort()
			return
		}

		entry := &cacheEntry{
			username:       username,
			namespace:      namespace,
			serviceAccount: saName,
		}
		s.tokenCache.Set(token, entry)

		c.Set("username", username)
		c.Set("namespace", namespace)
		c.Set("serviceAccount", saName)
		c.Next()
	}
}

func validateServiceAccountToken(clientset kubernetes.Interface, token, namespace string) (string, string, string, error) {
	tokenReview := &authv1.TokenReview{
		Spec: authv1.TokenReviewSpec{
			Token: token,
		},
	}

	result, err := clientset.AuthenticationV1().TokenReviews().Create(
		context.Background(),
		tokenReview,
		metav1.CreateOptions{},
	)
	if err != nil {
		return "", "", "", fmt.Errorf("failed to validate token: %w", err)
	}

	if !result.Status.Authenticated {
		return "", "", "", fmt.Errorf("token not authenticated")
	}

	username := result.Status.User.Username
	parts := strings.Split(username, ":")
	if len(parts) != 4 || parts[0] != "system" || parts[1] != "serviceaccount" {
		return "", "", "", fmt.Errorf("invalid service account username format")
	}

	serviceAccountNS := parts[2]
	saName := parts[3]

	if namespace != "" && serviceAccountNS != namespace {
		return "", "", "", fmt.Errorf("service account namespace mismatch")
	}

	return username, serviceAccountNS, saName, nil
}

