	if err != nil {
		rollback = true
		return nil, fmt.Errorf("failed to resolve pod IP: %w", err)
	}

	sandboxInfo := &types.SandboxInfo{
		Kind:             req.Kind,
		SandboxID:        sessionID,
		SandboxNamespace: req.Namespace,
		Name:             req.Name,
		SessionID:        sessionID,
		CreatedAt:        time.Now(),
		ExpiresAt:        time.Now().Add(DefaultSandboxTTL),
		Status:           "Running",
		EntryPoints:      buildEntryPoints(podIP, s.config.Port),
	}

	return sandboxInfo, nil
}

func (s *Server) deleteSandboxBySession(ctx context.Context, sessionID, kind string) error {
	return nil
}

func resolvePodIP(ctx context.Context, dynamicClient dynamic.Interface, namespace, sandboxName string) (string, error) {
	pod, err := tryGetPodByName(ctx, dynamicClient, namespace, sandboxName)
	if err == nil && pod != nil {
		if isPodRunning(pod) {
			return pod.Status.PodIP, nil
		}
		return "", fmt.Errorf("pod %s is not running", sandboxName)
	}

	sandbox, err := dynamicClient.Resource(SandboxGVR).Namespace(namespace).Get(ctx, sandboxName, metav1.GetOptions{})
	if err == nil {
		annotations := sandbox.GetAnnotations()
		if podName, ok := annotations["agents.x-k8s.io/sandbox-pod-name"]; ok && podName != "" {
			pod, err := tryGetPodByName(ctx, dynamicClient, namespace, podName)
			if err == nil && pod != nil && isPodRunning(pod) {
				return pod.Status.PodIP, nil
			}
		}
	}

	pods, err := dynamicClient.Resource(corev1.SchemeGroupVersion.WithResource("pods")).
		Namespace(namespace).
		List(ctx, metav1.ListOptions{
			LabelSelector: fmt.Sprintf("runtime.agentcube.io/sandbox-name=%s", sandboxName),
		})
	if err != nil {
		return "", fmt.Errorf("failed to list pods: %w", err)
	}

	for i := range pods.Items {
		var typedPod corev1.Pod
		if err := convertUnstructuredToPod(&pods.Items[i], &typedPod); err != nil {
			continue
		}
		if isPodRunning(&typedPod) && hasSandboxControllerOwner(&typedPod, sandboxName) {
			podIP := typedPod.Status.PodIP
			if podIP != "" {
				return podIP, nil
			}
		}
	}

	return "", fmt.Errorf("no running pod found for sandbox %s", sandboxName)
}

func tryGetPodByName(ctx context.Context, dynamicClient dynamic.Interface, namespace, name string) (*corev1.Pod, error) {
	pod, err := dynamicClient.Resource(corev1.SchemeGroupVersion.WithResource("pods")).
		Namespace(namespace).
		Get(ctx, name, metav1.GetOptions{})
	if err != nil {
		return nil, err
	}

	var typedPod corev1.Pod
	if err := convertUnstructuredToPod(pod, &typedPod); err != nil {
		return nil, err
	}

	return &typedPod, nil
}

func convertUnstructuredToPod(u *unstructured.Unstructured, pod *corev1.Pod) error {
	data, err := u.MarshalJSON()
	if err != nil {
		return err
	}
	return json.Unmarshal(data, pod)
}

func isPodRunning(pod *corev1.Pod) bool {
	if pod.Status.Phase != corev1.PodRunning {
		return false
	}
	return pod.Status.PodIP != ""
}

func hasSandboxControllerOwner(pod *corev1.Pod, sandboxName string) bool {
	ownerRef := getSandboxControllerOwner(pod)
	if ownerRef == nil {
		return false
	}
	return ownerRef.Kind == "Sandbox" && ownerRef.Name == sandboxName
}

func getSandboxControllerOwner(pod *corev1.Pod) *metav1.OwnerReference {
	for i := range pod.OwnerReferences {
		ref := &pod.OwnerReferences[i]
		if ref.Kind == "Sandbox" && ref.Controller != nil && *ref.Controller {
			return ref
		}
	}
	return nil
}

func buildEntryPoints(podIP string, port int) []types.SandboxEntryPoint {
	return []types.SandboxEntryPoint{
		{
			Path:     "/",
			Protocol: "HTTP",
			Endpoint: fmt.Sprintf("%s:%d", podIP, port),
		},
	}
}

func (s *Server) rollbackSandbox(ctx context.Context, kind, namespace, name string) {
	timeoutCtx, cancel := context.WithTimeout(ctx, 30*time.Second)
	defer cancel()

	var gvr schema.GroupVersionResource
	if kind == "sandboxes" || kind == "sandbox.x-k8s.io, Resource=sandboxes" {
		gvr = SandboxGVR
	} else if kind == "sandboxclaims" || kind == "sandbox.x-k8s.io, Resource=sandboxclaims" {
		gvr = SandboxClaimGVR
	} else {
		gvr = SandboxGVR
	}

	err := s.k8sClient.dynamicClient.Resource(gvr).Namespace(namespace).Delete(timeoutCtx, name, metav1.DeleteOptions{})
	if err != nil {
		if k8serrors.IsNotFound(err) {
			return
		}
	}
}

