	"k8s.io/apimachinery/pkg/runtime/schema"
)

type garbageCollector struct {
	k8sClient   *K8sClient
	interval    time.Duration
	storeClient store.Store
	ctx         context.Context
	cancel      context.CancelFunc
}

func newGarbageCollector(k8sClient *K8sClient, storeClient store.Store) *garbageCollector {
	ctx, cancel := context.WithCancel(context.Background())
	return &garbageCollector{
		k8sClient:   k8sClient,
		interval:    15 * time.Second,
		storeClient: storeClient,
		ctx:         ctx,
		cancel:      cancel,
	}
}

func (gc *garbageCollector) Start(ctx context.Context) {
	ticker := time.NewTicker(gc.interval)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			return
		case <-gc.ctx.Done():
			return
		case <-ticker.C:
			gc.runGC(ctx)
		}
	}
}

func (gc *garbageCollector) Stop() {
	gc.cancel()
}

func (gc *garbageCollector) runGC(ctx context.Context) {
	gcCtx, cancel := context.WithTimeout(ctx, 2*time.Minute)
	defer cancel()

	inactiveTime := time.Now().Add(-DefaultSandboxIdleTimeout)
	inactive, err := gc.listInactiveSandboxes(gcCtx, inactiveTime, 16)
	if err != nil {
		return
	}

	expired, err := gc.listExpiredSandboxes(gcCtx, time.Now(), 16)
	if err != nil {
		return
	}

	merged := gc.mergeSandboxLists(inactive, expired)

	for _, sandbox := range merged {
		gc.deleteSandbox(gcCtx, sandbox)
	}
}

func (gc *garbageCollector) mergeSandboxLists(inactive, expired []*types.SandboxInfo) []*types.SandboxInfo {
	seen := make(map[string]bool)
	result := make([]*types.SandboxInfo, 0, len(inactive)+len(expired))

	for _, s := range inactive {
		if !seen[s.SessionID] {
			seen[s.SessionID] = true
			result = append(result, s)
		}
	}

	for _, s := range expired {
		if !seen[s.SessionID] {
			seen[s.SessionID] = true
			result = append(result, s)
		}
	}

	return result
}

func (gc *garbageCollector) listInactiveSandboxes(ctx context.Context, cutoff time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if gc.storeClient == nil {
		return nil, nil
	}
	return gc.storeClient.ListInactiveSandboxes(ctx, cutoff, limit)
}

func (gc *garbageCollector) listExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if gc.storeClient == nil {
		return nil, nil
	}
	return gc.storeClient.ListExpiredSandboxes(ctx, before, limit)
}

func (gc *garbageCollector) deleteSandbox(ctx context.Context, sandbox *types.SandboxInfo) {
	if sandbox == nil {
		return
	}

	var gvr schema.GroupVersionResource
	if sandbox.Kind == types.SandboxClaimsKind {
		gvr = SandboxClaimGVR
	} else {
		gvr = SandboxGVR
	}

	err := gc.k8sClient.dynamicClient.Resource(gvr).Namespace(sandbox.SandboxNamespace).Delete(ctx, sandbox.Name, metav1.DeleteOptions{})
	if err != nil && !k8serrors.IsNotFound(err) {
		return
	}

	if gc.storeClient != nil {
		gc.storeClient.DeleteSandboxBySessionID(ctx, sandbox.SessionID)
	}
}

