package router

import (
	"net/http"

	"github.com/gin-gonic/gin"
)

const DefaultMaxConcurrentRequests = 1000

func ConcurrencyMiddleware(maxRequests int) gin.HandlerFunc {
	if maxRequests <= 0 {
		maxRequests = DefaultMaxConcurrentRequests
	}

	semaphore := make(chan struct{}, maxRequests)

	return func(c *gin.Context) {
		select {
		case semaphore <- struct{}{}:
			defer func() { <-semaphore }()
			c.Next()
		default:
			c.JSON(http.StatusTooManyRequests, gin.H{
				"error": "server overloaded, please try again later",
				"code":  "SERVER_OVERLOADED",
			})
			c.Abort()
			return
		}
	}
}

