package picod

import (
	"fmt"
	"os"
	"path/filepath"
)

func sanitizePath(p string, workspace string) (string, error) {
	if workspace == "" {
		workspace = "/workspace"
	}

	resolvedWorkspace, err := filepath.EvalSymlinks(workspace)
	if err != nil {
		if !os.IsNotExist(err) {
			return "", fmt.Errorf("failed to resolve workspace symlinks: %w", err)
		}
		resolvedWorkspace = workspace
	}

	cleanPath := filepath.Clean(p)
	targetPath := filepath.Join(resolvedWorkspace, cleanPath)

	_, err = os.Lstat(targetPath)
	if err != nil {
		if os.IsNotExist(err) {
			if !filepath.HasPrefix(filepath.Clean(targetPath), resolvedWorkspace) {
				return "", fmt.Errorf("path escapes workspace")
			}
			return targetPath, nil
		}
		return "", fmt.Errorf("failed to stat path: %w", err)
	}

	resolvedPath, err := filepath.EvalSymlinks(targetPath)
	if err != nil {
		if !os.IsNotExist(err) {
			return "", fmt.Errorf("failed to resolve path symlinks: %w", err)
		}
		return targetPath, nil
	}

	if !filepath.HasPrefix(resolvedPath, resolvedWorkspace) {
		return "", fmt.Errorf("path escapes workspace")
	}

	return resolvedPath, nil
}

func getWorkspaceDir(workspaceFlag string) (string, error) {
	if workspaceFlag != "" {
		resolved, err := filepath.EvalSymlinks(workspaceFlag)
		if err != nil {
			return workspaceFlag, nil
		}
		return resolved, nil
	}

	wd, err := os.Getwd()
	if err != nil {
		return "", fmt.Errorf("failed to get working directory: %w", err)
	}

	resolved, err := filepath.EvalSymlinks(wd)
	if err != nil {
		return wd, nil
	}

	return resolved, nil
}

