package picod

import (
	"bytes"
	"context"
	"os"
	"os/exec"
	"time"

	"github.com/gin-gonic/gin"
)

type ExecuteRequest struct {
	Command    []string          `json:"command"`
	Timeout    string            `json:"timeout,omitempty"`
	WorkingDir string            `json:"working_dir,omitempty"`
	Env        map[string]string `json:"env,omitempty"`
}

type ExecuteResponse struct {
	Stdout    string  `json:"stdout"`
	Stderr    string  `json:"stderr"`
	ExitCode  int     `json:"exit_code"`
	Duration float64 `json:"duration"`
	StartTime string  `json:"start_time"`
	EndTime   string  `json:"end_time"`
}

func (s *Server) ExecuteHandler(c *gin.Context) {
	var req ExecuteRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}

	if len(req.Command) == 0 {
		c.JSON(400, gin.H{"error": "command is required"})
		return
	}

	var timeout time.Duration
	if req.Timeout == "" {
		timeout = 60 * time.Second
	} else {
		var err error
		timeout, err = time.ParseDuration(req.Timeout)
		if err != nil {
			c.JSON(400, gin.H{"error": "invalid timeout format"})
			return
		}
	}

	ctx, cancel := context.WithTimeout(c.Request.Context(), timeout)
	defer cancel()

	cmd := exec.CommandContext(ctx, req.Command[0], req.Command[1:]...)

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	cmd.Env = os.Environ()
	for k, v := range req.Env {
		cmd.Env = append(cmd.Env, k+"="+v)
	}

	if req.WorkingDir != "" {
		sanitizedWd, err := sanitizePath(req.WorkingDir, s.workspaceDir)
		if err != nil {
			c.JSON(400, gin.H{"error": "invalid working directory"})
			return
		}
		cmd.Dir = sanitizedWd
	}

	startTime := time.Now()
	startTimeStr := startTime.Format("2006-01-02T15:04:05Z07:00")

	err := cmd.Run()

	endTime := time.Now()
	endTimeStr := endTime.Format("2006-01-02T15:04:05Z07:00")
	duration := endTime.Sub(startTime).Seconds()

	resp := ExecuteResponse{
		StartTime: startTimeStr,
		EndTime:   endTimeStr,
		Duration:  duration,
	}

	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			resp.ExitCode = exitErr.ExitCode()
			resp.Stderr = stderr.String()
		} else if ctx.Err() == context.DeadlineExceeded {
			resp.ExitCode = 124
			resp.Stderr = stderr.String() + "command timed out"
		} else {
			resp.ExitCode = 1
			resp.Stderr = err.Error()
		}
	} else {
		resp.ExitCode = 0
		resp.Stdout = stdout.String()
	}

	c.JSON(200, resp)
}

